import{_ as n,c as a,a as e,o as i}from"./app-CEcM0piI.js";const l={};function t(p,s){return i(),a("div",null,s[0]||(s[0]=[e(`<p>将项目按照功能拆分成若干个子模块，方便项目的管理维护、扩展，也方便模块间的相互调用，资源共享。</p><h1 id="继承" tabindex="-1"><a class="header-anchor" href="#继承"><span>继承</span></a></h1><p>概念：继承描述的是两个工程间的关系，与java中的继承相似，子工程可以继承父工程中的配置信息，常见于依赖关系的继承。</p><p>作用：简化依赖配置、统一管理依赖 在子工程的pom文件中使用&lt;parent&gt;标签引入父工程的坐标 父工程的打包方式也要选择为pom,需要在maven的配置文件中使用&lt;packing&gt;标签设置为pom打包方式</p><p>父标签中的&lt;relativePath&gt;标签表明父工程的路径,如果是自己创建的工程需要使用这个标签手动指明父工程pom.xml的相对路径 如果不写默认是先在本地仓库查找,如果没有再去远程仓库查找,远程仓库有就下载到本地仓库</p><p>假设当前工程和父工程在同一文件夹下</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;relativePath&gt;../tlias-parent/pom.xml&lt;/relativePath&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>需要先往上一级找到父工程与当前工程所在文件夹,接着进入父工程找到父工程的pom文件</p><p><strong>打包方式</strong></p><ul><li>jar：普通模块打包，springboot项目基本都是jar包（内嵌tomcat运行）</li><li>war：普通web程序打包，需要部署在外部的tomcat服务器中运行</li><li>pom：父工程或聚合工程，该模块不写代码，仅进行依赖管理</li></ul><p>如果父工程和子工程配置了不同版本的相同依赖那么以子工程为准</p><h2 id="版本锁定" tabindex="-1"><a class="header-anchor" href="#版本锁定"><span>版本锁定</span></a></h2><p>在maven中，可以在父工程的pom文件中通过&lt;dependencyManagement&gt;来统一管理依赖版本。 子工程引l入依赖时，无需指定&lt;version&gt;版本号，父工程统一管理。变更依赖版本，只需在父工程中统一变更。</p><h2 id="自定义属性-引用属性" tabindex="-1"><a class="header-anchor" href="#自定义属性-引用属性"><span>自定义属性/引用属性</span></a></h2><p>可以在properties标签中同一管理依赖的版本,在引入依赖时使用这里的属性</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;properties&gt;</span></span>
<span class="line"><span>	&lt;lombok.version&gt;1.18.24&lt;/lombok.version&gt;</span></span>
<span class="line"><span>	&lt;jjwt.version&gt;0.9.0&lt;/jjwt.version&gt;</span></span>
<span class="line"><span>&lt;/properties&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;dependency&gt;</span></span>
<span class="line"><span>	&lt;groupId&gt;io.jsonwebtoken&lt;/groupId&gt;</span></span>
<span class="line"><span>	&lt;artifactId&gt;jjwt&lt;/artifactId&gt;</span></span>
<span class="line"><span>	&lt;version&gt;\${jjwt.version}&lt;/version&gt;</span></span>
<span class="line"><span>&lt;/dependency&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="聚合" tabindex="-1"><a class="header-anchor" href="#聚合"><span>聚合</span></a></h1><p>当完成好工程后需要将工程安装到本地仓库可以使用maven命令安装,但如果工程较多需要一个个安装且安装时如果一个子工程依赖的父工程没有安装就会报错,只有等父工程安装后子工程才能正常安装</p><p>聚合就是将多个模块组织成一个整体同时进行项目的构建</p><p><strong>聚合工程</strong> 一个不具有业务功能的“空”工程（有且仅有一个pom文件）</p><p>通常来说一个父工程也是一个聚合工程,因为父工程不具备业务功能只是管理依赖</p><p>作用 : 快速构建项目（无需根据依赖关系手动构建，直接在聚合工程上构建即可）</p><p>maven中可以通过&lt;modules&gt;设置当前聚合工程所包含的子模块名称</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;modules&gt;</span></span>
<span class="line"><span>	&lt;module&gt;../tlias-pojo&lt;/module&gt;</span></span>
<span class="line"><span>	&lt;module&gt;../tlias-utils&lt;/module&gt;</span></span>
<span class="line"><span>	&lt;module&gt;../tlias-web-management&lt;/module&gt;</span></span>
<span class="line"><span>&lt;/modules&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>聚合工程执行什么maven命令与其聚合的模块也会执行</p><h1 id="私服" tabindex="-1"><a class="header-anchor" href="#私服"><span>私服</span></a></h1><p>一般来说私服有三个仓库:</p><ol><li>CENTER(中央) : 里面存放着从中央仓库拉取的模块</li><li>RELEASE（发行版本）：功能趋于稳定、当前更新停止，可以用于发行的版本，存储在私服中的RELEASE仓库中。</li><li>SNAPSHOT（快照版本）：功能不稳定、尚处于开发中的版本，即快照版本，存储在私服的SNAPSHOT仓库中。</li></ol><p>当创建maven工程时pom文件中会有一个描述当前工程版本的标签version标签如果版本号带有SNAPSHOT就会存放在SNAPSHOT仓库中,如果没有SNAPSHOT字段就会存放在RELEASE仓库中</p><p><strong>设置私服的访问用户名/密码（settings.xml中的servers中配置）</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;--!release仓库用户名和密码--&gt;</span></span>
<span class="line"><span>&lt;server&gt;</span></span>
<span class="line"><span>	&lt;id&gt;maven-releases&lt;/id&gt;</span></span>
<span class="line"><span>	&lt;username&gt;admin&lt;/username&gt;</span></span>
<span class="line"><span>	&lt;password&gt;admin&lt;/password&gt;</span></span>
<span class="line"><span>&lt;/server&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;--!snapshots用户名和密码--&gt;</span></span>
<span class="line"><span>&lt;server&gt;</span></span>
<span class="line"><span>	&lt;id&gt;maven-snapshots&lt;/id&gt;</span></span>
<span class="line"><span>	&lt;username&gt;admin&lt;/username&gt;</span></span>
<span class="line"><span>	&lt;password&gt;admin&lt;/password&gt;</span></span>
<span class="line"><span>&lt;/server&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>自己创建maven工程的pom文件中配置上传（发布）地址</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;distributionManagement&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>	&lt;--!release版本--&gt;</span></span>
<span class="line"><span>	&lt;repository&gt;</span></span>
<span class="line"><span>		&lt;id&gt;maven-releases&lt;/id&gt;</span></span>
<span class="line"><span>		&lt;ur1&gt;http://192.168.150.101:8081/repository/maven-releases/&lt;/url&gt;</span></span>
<span class="line"><span>	&lt;/repository&gt;</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	&lt;--!release版本--&gt;</span></span>
<span class="line"><span>	&lt;snapshotRepository&gt;</span></span>
<span class="line"><span>		&lt;id&gt;maven-snapshots&lt;/id&gt;</span></span>
<span class="line"><span>		&lt;ur1&gt;http://192.168.150.101:8081/repository/maven-snapshots/&lt;/url&gt;</span></span>
<span class="line"><span>	&lt;/snapshotRepository&gt;</span></span>
<span class="line"><span>&lt;/distributionManagement&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>设置私服依赖下载的仓库组地址（settings.xml中的mirrors、profiles中配置）</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;mirror&gt;</span></span>
<span class="line"><span>	&lt;id&gt;maven-public&lt;/id&gt;</span></span>
<span class="line"><span>	&lt;mirrorof&gt;*&lt;/mirrorof&gt;</span></span>
<span class="line"><span>	&lt;url&gt;http://192.168.150.101:8081/repository/maven-pub1ic/&lt;/url&gt;</span></span>
<span class="line"><span>&lt;/mirror&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,35)]))}const r=n(l,[["render",t]]),c=JSON.parse('{"path":"/back/maven/2/","title":"2 高级","lang":"zh-CN","frontmatter":{"title":"2 高级","createTime":"2025/06/18 20:59:30","permalink":"/back/maven/2/"},"readingTime":{"minutes":3.8,"words":1139},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/Maven/2 高级.md","headers":[]}');export{r as comp,c as data};
